// Defensive cross-node access. n8n throws when referencing a node that
// hasn't been executed (e.g. upstream Postgres step returned 0 items, or
// `executeOnce`+`continueOnFail` left it without an output run). Wrap each
// $() access so the report still goes out with partial data.
function safeFirst(node) {
  try { return $(node).first()?.json ?? {}; } catch { return {}; }
}
function safeAll(node) {
  try { return $(node).all().map(i => i.json); } catch { return []; }
}

const dbInfo = safeFirst('DB size & counts');
const tables = safeAll('Top 5 tables by size');
const slow = safeAll('Slow queries (pg_stat_statements)').filter(r => !r.error);

const tableLines = tables.map(t =>
  `  \`${t.table_name}\` вАФ ${t.total_size} (${Number(t.row_count).toLocaleString()} rows)`
).join('\n') || '  вАФ';

const slowLines = slow.length
  ? slow.map(q => `  ${q.avg_ms}ms (√Ч${q.calls}) \`${q.query_preview}\``).join('\n')
  : '  pg\_stat\_statements –љ–µ –≤—Б—В–∞–љ–Њ–≤–ї–µ–љ–Њ –∞–±–Њ –љ–µ–Љ–∞—Ф –і–∞–љ–Є—Е';

const text = [
  `рЯЧД *DB: ${dbInfo.db_name ?? 'unknown'}*`,
  `рЯУ¶ –†–Њ–Ј–Љ—Ц—А: \`${dbInfo.db_size ?? 'unknown'}\``,
  `рЯС• –Ъ–Њ—А–Є—Б—В—Г–≤–∞—З—Ц–≤: ${dbInfo.user_count ?? 'вАФ'}`,
  `рЯТ≥ –Ґ—А–∞–љ–Ј–∞–Ї—Ж—Ц–є Mono: ${dbInfo.tx_count != null ? Number(dbInfo.tx_count).toLocaleString() : 'вАФ'}`,
  `рЯФФ Push-–њ—Ц–і–њ–Є—Б–Њ–Ї: ${dbInfo.active_push_subs ?? 'вАФ'}`,
  ``,
  `рЯУЛ *–Ґ–Њ–њ —В–∞–±–ї–Є—Ж—Ц:*`,
  tableLines,
  ``,
  `рЯРҐ *–Я–Њ–≤—Ц–ї—М–љ—Ц –Ј–∞–њ–Є—В–Є:*`,
  slowLines,
].join('\n');

return [{ json: { text } }];
